async function validateFunctionCalls(run) {
  if (run.last_error) return;

  const schemaViolations = [];

  for (const toolCall of run.required_action?.submit_tool_outputs?.tool_outputs || []) {
    const func = toolCall.function;
    if (func.arguments) {
      try {
        const args = JSON.parse(func.arguments);
        // Check required params exist
        if (!args.param1) {
          schemaViolations.push(`Missing required param1 in ${func.name}`);
        }
      } catch (e) {
        schemaViolations.push(`Invalid JSON in ${func.name}: ${e.message}`);
      }
    }
  }

  if (schemaViolations.length > 0) {
    console.log('🚨 Schema violations:', schemaViolations);
  }
}

