const functionSchemas = {
  weather: {
    type: 'object',
    properties: {
      lat: { type: 'number' },
      lon: { type: 'number' }
    },
    required: ['lat', 'lon'],
    additionalProperties: false
  }
};

async function validateAndSubmitTools(run) {
  const toolOutputs = [];

  for (const toolCall of run.required_action.submit_tool_outputs.tool_outputs) {
    const func = toolCall.function;
    const args = JSON.parse(func.arguments);

    const validate = ajv.compile(functionSchemas[func.name]);
    if (!validate(args)) {
      throw new Error(`Schema violation in ${func.name}: ${JSON.stringify(validate.errors)}`);
    }

    toolOutputs.push({
      tool_call_id: toolCall.id,
      output: 'validated'
    });
  }

  return client.beta.threads.runs.submit_tool_outputs(
    threadId, runId, { tool_outputs: toolOutputs }
  );
}

