def test_openai_assistant(run: dict):
    failures = []

    # Test 1: Sandbox errors
    if run.get('last_error') and 'sandbox' in run['last_error']['message'].lower():
        failures.append('sandbox_error')

    # Test 2: Context bloat
    thread = client.beta.threads.retrieve(run['thread_id'])
    if len(thread.messages.data) > 50:
        failures.append('context_bloat')

    # Test 3: Function schema violations
    tool_calls = run.get('required_action', {}).get('submit_tool_outputs', {}).get('tool_outputs', [])
    for tool in tool_calls:
        try:
            args = json.loads(tool['function']['arguments'])
            if 'invalid_param' not in args:  # Schema check
                failures.append('schema_violation')
        except:
            failures.append('json_parse_error')

    if failures:
        vex.record_failure(run['thread_id'], failures, severity='high')
